// ============================================================
// WF5 — Image Sync: portada + hasta 3 imágenes extra
// - Fase 1: productos SIN image_1920 → retry portada desde Syscom
// - Fase 2: todos los productos → hasta 3 imágenes extra via product.image
// - Usa endpoint individual /api/v1/productos/{id} para array imagenes
// ============================================================

const ODOO_URL = "https://ocean-tech.odoo.com/jsonrpc";
const DB = "ocean-tech", UID = 2, PWD = "M1ercole$";
const SYSCOM_CLIENT = "zq2u2Zr1VFGam5IzAg5UolwmeSnsChP7";
const SYSCOM_SECRET = "thdUXtjZunSRT4IB1ascUHIZlWsA5PhtIL9mBWVz";
const BATCH_SIZE = 10; // menos productos por batch = menos presión en Odoo y Syscom
const MAX_EXTRA_IMAGES = 3;

const sleep = ms => new Promise(r => setTimeout(r, ms));

async function odoo(model, method, args, kwargs={}) {
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method:"POST", url:ODOO_URL, json:true,
        body:{jsonrpc:"2.0",method:"call",id:Date.now(),
          params:{service:"object",method:"execute_kw",
            args:[DB,UID,PWD,model,method,args],kwargs}}
      });
      if (resp.error) throw new Error(JSON.stringify(resp.error.data||resp.error).substring(0,500));
      return resp.result;
    } catch(e) {
      const msg = String(e.message);
      if (attempt < 2 && (msg.includes("429") || msg.includes("Too Many") || msg.includes("503"))) {
        await sleep((attempt + 1) * 5000);
        continue;
      }
      throw e;
    }
  }
}

async function getSyscomToken() {
  const resp = await this.helpers.httpRequest({
    method:"POST", url:"https://developers.syscom.mx/oauth/token",
    headers:{"Content-Type":"application/x-www-form-urlencoded"},
    body:"client_id="+SYSCOM_CLIENT+"&client_secret="+SYSCOM_SECRET+"&grant_type=client_credentials"
  });
  return resp.access_token;
}

async function imgToBase64(url) {
  if (!url) return null;
  try {
    const resp = await this.helpers.httpRequest({
      method:"GET", url, encoding:"arraybuffer", options:{timeout:15000}
    });
    if (resp && resp.length > 500) return Buffer.from(resp).toString("base64");
    return null;
  } catch(e) { return null; }
}

async function getSyscomProduct(token, productoId) {
  try {
    const resp = await this.helpers.httpRequest({
      method:"GET",
      url:"https://developers.syscom.mx/api/v1/productos/" + productoId,
      headers:{Authorization:"Bearer " + token},
      json:true, options:{timeout:15000}
    });
    return resp;
  } catch(e) { return null; }
}

// === StaticData ===
const sd = $getWorkflowStaticData("global");
const inputItems = $input.all();
const body = inputItems[0]?.json?.body || inputItems[0]?.json || {};

if (body.action === "reset") {
  Object.keys(sd).forEach(k => delete sd[k]);
  return [{ json: { _reset:true, message:"RESET OK" } }];
}
if (body.action === "status") {
  return [{ json: {
    phase: sd.phase || "1_portada",
    offset: sd.offset || 0,
    portadaFixed: sd.portadaFixed || 0,
    extraAdded: sd.extraAdded || 0,
    processed: sd.processed || 0,
    errors: sd.errors || 0,
    done: sd.done || false
  }}];
}

// === Init ===
if (!sd.phase) sd.phase = "1_portada";
if (!sd.offset) sd.offset = 0;
if (!sd.portadaFixed) sd.portadaFixed = 0;
if (!sd.extraAdded) sd.extraAdded = 0;
if (!sd.processed) sd.processed = 0;
if (!sd.errors) sd.errors = 0;

if (sd.done) {
  return [{ json: { _done:true, message:"IMAGE SYNC COMPLETADO",
    portadaFixed:sd.portadaFixed, extraAdded:sd.extraAdded,
    processed:sd.processed, errors:sd.errors }}];
}

const token = await getSyscomToken.call(this);
const results = [];

// =============================================
// FASE 1: Productos sin imagen principal
// =============================================
if (sd.phase === "1_portada") {
  // Buscar productos sin image_1920 que tengan barcode (SKU Syscom)
  const prods = await odoo.call(this, "product.template", "search_read",
    [[["image_1920","=",false],["barcode","!=",false]]],
    {fields:["id","barcode","name"], limit:BATCH_SIZE, offset:sd.offset, order:"id asc"});

  if (!prods || prods.length === 0) {
    // Fase 1 terminada → pasar a fase 2
    sd.phase = "2_extra";
    sd.offset = 0;
    return [{ json: { status:"phase1_done", portadaFixed:sd.portadaFixed,
      message:"Pasando a fase 2 (imágenes extra)" }}];
  }

  for (const p of prods) {
    try {
      const sku = p.barcode;
      // Buscar en Syscom por categoría para obtener img_portada
      // Primero intentar buscar producto en listing
      const searchResp = await this.helpers.httpRequest({
        method:"GET",
        url:"https://developers.syscom.mx/api/v1/productos?busqueda=" + encodeURIComponent(sku) + "&moneda=MXN",
        headers:{Authorization:"Bearer " + token},
        json:true, options:{timeout:15000}
      });

      let imgUrl = null;
      const found = (searchResp.productos || []).find(sp => String(sp.modelo) === String(sku));
      if (found && found.img_portada) {
        imgUrl = found.img_portada;
      }

      if (imgUrl) {
        const b64 = await imgToBase64.call(this, imgUrl);
        if (b64) {
          await odoo.call(this, "product.template", "write", [[p.id], {image_1920: b64}]);
          sd.portadaFixed++;
          results.push({ json: { sku, op:"portada_fixed", prodId:p.id } });
        } else {
          results.push({ json: { sku, op:"portada_download_fail", prodId:p.id } });
        }
      } else {
        results.push({ json: { sku, op:"portada_not_found_syscom", prodId:p.id } });
      }
      sd.processed++;
      await sleep(300);
    } catch(err) {
      sd.errors++;
      results.push({ json: { sku:p.barcode||"?", op:"error", error:err.message.substring(0,200) } });
    }
  }

  sd.offset += prods.length;
  if (prods.length < BATCH_SIZE) {
    sd.phase = "2_extra";
    sd.offset = 0;
  }

  return results.length ? results : [{ json: { status:"phase1_batch", offset:sd.offset, portadaFixed:sd.portadaFixed }}];
}

// =============================================
// FASE 2: Imágenes extra (hasta 3 por producto)
// =============================================
if (sd.phase === "2_extra") {
  // Buscar productos con barcode que NO tengan ya imágenes extra
  const prods = await odoo.call(this, "product.template", "search_read",
    [[["barcode","!=",false],["image_1920","!=",false]]],
    {fields:["id","barcode","name","product_template_image_ids"], limit:BATCH_SIZE, offset:sd.offset, order:"id asc"});

  if (!prods || prods.length === 0) {
    sd.done = true;
    return [{ json: { _done:true, message:"IMAGE SYNC COMPLETADO",
      portadaFixed:sd.portadaFixed, extraAdded:sd.extraAdded,
      processed:sd.processed, errors:sd.errors }}];
  }

  for (const p of prods) {
    try {
      // Saltar si ya tiene imágenes extra
      const existingExtras = p.product_template_image_ids || [];
      if (existingExtras.length >= MAX_EXTRA_IMAGES) {
        results.push({ json: { sku:p.barcode, op:"skip_has_extras", count:existingExtras.length } });
        sd.processed++;
        continue;
      }

      const sku = p.barcode;

      // Buscar producto_id en Syscom via búsqueda
      const searchResp = await this.helpers.httpRequest({
        method:"GET",
        url:"https://developers.syscom.mx/api/v1/productos?busqueda=" + encodeURIComponent(sku) + "&moneda=MXN",
        headers:{Authorization:"Bearer " + token},
        json:true, options:{timeout:15000}
      });

      const found = (searchResp.productos || []).find(sp => String(sp.modelo) === String(sku));
      if (!found || !found.producto_id) {
        results.push({ json: { sku, op:"not_found_syscom" } });
        sd.processed++;
        await sleep(200);
        continue;
      }

      // Obtener detalle con imágenes
      const detail = await getSyscomProduct.call(this, token, found.producto_id);
      if (!detail || !detail.imagenes || detail.imagenes.length <= 1) {
        results.push({ json: { sku, op:"no_extra_images", syscomId:found.producto_id } });
        sd.processed++;
        await sleep(200);
        continue;
      }

      // Tomar imágenes extra (skip la primera que ya es portada)
      const extraImgs = detail.imagenes
        .filter((img, idx) => idx > 0 && img.imagen)
        .slice(0, MAX_EXTRA_IMAGES - existingExtras.length);

      let added = 0;
      for (let i = 0; i < extraImgs.length; i++) {
        const imgData = extraImgs[i];
        const b64 = await imgToBase64.call(this, imgData.imagen);
        if (b64) {
          await odoo.call(this, "product.image", "create", [{
            product_tmpl_id: p.id,
            name: p.name + " - Vista " + (existingExtras.length + i + 1),
            image_1920: b64,
            sequence: existingExtras.length + i + 1
          }]);
          added++;
          await sleep(200);
        }
      }

      sd.extraAdded += added;
      sd.processed++;
      results.push({ json: { sku, op:"extras_added", count:added, prodId:p.id, syscomId:found.producto_id } });
      await sleep(300);

    } catch(err) {
      sd.errors++;
      results.push({ json: { sku:p.barcode||"?", op:"error", error:err.message.substring(0,200) } });
    }
  }

  sd.offset += prods.length;
  return results.length ? results : [{ json: { status:"phase2_batch", offset:sd.offset, extraAdded:sd.extraAdded }}];
}

return [{ json: { error:"unknown phase", phase:sd.phase } }];
